import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Using StringBuilder to concatenate user input to a fixed size buffer
        StringBuilder fixedSizeBuffer = new StringBuilder("Fixed size buffer ");
        fixedSizeBuffer.append(userInput);

        System.out.println("Resulting string: " + fixedSizeBuffer.toString());
    }
}

